func computeFeeBreakdown(db *sql.DB, sku, asin string, minFeePct float64) ([]map[string]any, error) {
	rows, err := db.Query(`SELECT sku, asin, product_name, your_price, referral_fee, fba_pick_pack, fba_weight_handling, fba_order_handling, fba_fulfillment_fee, closing_fee, estimated_fee_total FROM fee_estimates`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var row struct {
			sku, asin, name                                                                   sql.NullString
			price, referral, pickPack, weight, handling, fulfillment, closing, estimatedTotal sql.NullFloat64
		}
		if err := rows.Scan(&row.sku, &row.asin, &row.name, &row.price, &row.referral, &row.pickPack, &row.weight, &row.handling, &row.fulfillment, &row.closing, &row.estimatedTotal); err != nil {
			return nil, err
		}
		if sku != "" && row.sku.String != sku {
			continue
		}
		if asin != "" && row.asin.String != asin {
			continue
		}
		price := row.price.Float64
		total := row.estimatedTotal.Float64
		if total == 0 {
			total = row.referral.Float64 + row.pickPack.Float64 + row.weight.Float64 + row.handling.Float64 + row.fulfillment.Float64 + row.closing.Float64
		}
		feePct := pct(total, price)
		if minFeePct > 0 && feePct < minFeePct {
			continue
		}
		out = append(out, map[string]any{
			"sku": row.sku.String, "asin": row.asin.String, "product_name": row.name.String,
			"your_price": price, "referral_fee": row.referral.Float64, "referral_fee_pct": pct(row.referral.Float64, price),
			"fba_pick_pack": row.pickPack.Float64, "fba_weight_handling": row.weight.Float64, "fba_order_handling": row.handling.Float64,
			"fba_total":   row.pickPack.Float64 + row.weight.Float64 + row.handling.Float64 + row.fulfillment.Float64,
			"closing_fee": row.closing.Float64, "estimated_total_fee": total, "fee_as_pct_of_price": feePct,
		})
	}
	return out, rows.Err()
}

func computeSKUPnl(db *sql.DB, sku, asin string, minUnits int, sortBy string, sinceDate string) ([]map[string]any, error) {
	rows, err := db.Query(`WITH order_rollup AS (
			SELECT sku, COALESCE(MAX(asin), '') AS asin, SUM(quantity) AS units, SUM(item_price + shipping_price) AS revenue
			FROM order_details WHERE purchase_date >= ? GROUP BY sku
		), storage_rollup AS (
			SELECT sku, SUM(monthly_storage_fee + lts_12mo_fee) AS storage_fee
			FROM storage_fees GROUP BY sku
		)
		SELECT o.sku, o.asin, o.units, o.revenue,
			COALESCE(f.product_name, ''), COALESCE(f.referral_fee, 0),
			COALESCE(f.fba_fulfillment_fee + f.fba_pick_pack + f.fba_weight_handling + f.fba_order_handling, 0),
			COALESCE(s.storage_fee, 0)
		FROM order_rollup o
		LEFT JOIN fee_estimates f ON f.sku = o.sku
		LEFT JOIN storage_rollup s ON s.sku = o.sku`, sinceDate)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var skuVal, asinVal, name string
		var units int
		var revenue, referralPerUnit, fbaPerUnit, storageFee float64
		if err := rows.Scan(&skuVal, &asinVal, &units, &revenue, &name, &referralPerUnit, &fbaPerUnit, &storageFee); err != nil {
			return nil, err
		}
		if sku != "" && skuVal != sku {
			continue
		}
		if asin != "" && asinVal != asin {
			continue
		}
		if minUnits > 0 && units < minUnits {
			continue
		}
		referral := referralPerUnit * float64(units)
		fba := fbaPerUnit * float64(units)
		estimatedProfit := revenue - referral - fba - storageFee
		out = append(out, map[string]any{
			"sku": skuVal, "asin": asinVal, "product_name": name, "units_sold": units, "revenue": revenue,
			"avg_selling_price": safeDiv(revenue, float64(units)), "referral_fee_total": referral, "fba_fee_total": fba,
			"storage_fee_total": storageFee, "estimated_profit": estimatedProfit, "margin_pct": pct(estimatedProfit, revenue),
		})
	}
	sort.Slice(out, func(i, j int) bool {
		return numericField(out[i], sortField(sortBy)) > numericField(out[j], sortField(sortBy))
	})
	return out, rows.Err()
}

func computeSettlementReconciliation(db *sql.DB, minDiscrepancy float64) ([]map[string]any, error) {
	rows, err := db.Query(`SELECT o.order_id, o.sku, SUM(o.item_price + o.shipping_price), COALESCE(SUM(s.amount), 0)
		FROM order_details o LEFT JOIN settlements s ON s.order_id = o.order_id AND (s.sku = o.sku OR s.sku = '')
		GROUP BY o.order_id, o.sku`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []map[string]any
	for rows.Next() {
		var orderID, sku string
		var expected, actual float64
		if err := rows.Scan(&orderID, &sku, &expected, &actual); err != nil {
			return nil, err
		}
		discrepancy := actual - expected
		if minDiscrepancy > 0 && abs(discrepancy) < minDiscrepancy {
			continue
		}
		out = append(out, map[string]any{
			"order_id": orderID, "sku": sku, "expected_settlement": expected, "actual_settlement": actual,
			"discrepancy": discrepancy, "discrepancy_pct": pct(discrepancy, expected),
			"note": "expected_settlement is an estimate from order revenue; settlements can differ because of refunds, chargebacks, reserves, tax, and settlement timing",
		})
	}
	return out, rows.Err()
}

func computeReimbursements(db *sql.DB, sinceDate string) ([]map[string]any, error) {
	rows, err := db.Query(`SELECT sku, asin, reason, SUM(quantity_reimbursed), SUM(amount), MAX(approval_date) FROM reimbursements WHERE approval_date >= ? GROUP BY sku, asin, reason ORDER BY SUM(amount) DESC`, sinceDate)
	if err != nil {
		return nil, err
	}
	return scanRows(rows)
}

func sortField(sortBy string) string {
	switch strings.ToLower(sortBy) {
	case "revenue":
		return "revenue"
	case "margin":
		return "margin_pct"
	case "units":
		return "units_sold"
	default:
		return "estimated_profit"
	}
}

func pct(n, d float64) float64 {
	if d == 0 {
		return 0
	}
	return n / d * 100
}

func abs(v float64) float64 {
	if v < 0 {
		return -v
	}
	return v
}

func numericField(m map[string]any, k string) float64 {
	switch v := m[k].(type) {
	case float64:
		return v
	case int:
		return float64(v)
	}
	return 0
}

func lowerContains(s, sub string) bool {
	return strings.Contains(strings.ToLower(s), strings.ToLower(sub))
}
